import os,sys,time,json,requests

def load_cfg():
    p='/run/connector.json'
    try:
        with open(p,'r',encoding='utf-8') as f:
            return json.load(f)
    except Exception as e:
        print(json.dumps({'error':'Failed to load connector.json','file':'main.py','details':str(e)})); sys.exit(1)

cfg=load_cfg()
auth=cfg.get('auth',{}) or {}
conf=cfg.get('configuration',{}) or {}
base_url=(conf.get('jiraBaseUrl') or '').strip()
issue_key=(conf.get('issueKey') or '').strip()
user_account_id=conf.get('userAccountId')
assignee_name=conf.get('assigneeName')
user_email=conf.get('userEmail')
try:
    timeout_s=int(conf.get('timeoutSeconds',60))
except Exception:
    timeout_s=60
try:
    interval_s=float(conf.get('pollIntervalSeconds',5))
except Exception:
    interval_s=5.0
interval_s=interval_s if interval_s>0 else 1.0
email=(auth.get('email') or '').strip()
api_token=(auth.get('apiToken') or '').strip()
missing=[]
if not base_url: missing.append('configuration.jiraBaseUrl')
if not issue_key: missing.append('configuration.issueKey')
if not email: missing.append('auth.email')
if not api_token: missing.append('auth.apiToken')
if missing:
    print(json.dumps({'error':'Missing required fields','file':'main.py','missing':missing})); sys.exit(1)
if not (user_account_id or assignee_name or user_email):
    print(json.dumps({'error':'Provide at least one of configuration.userAccountId, configuration.assigneeName, configuration.userEmail','file':'main.py'})); sys.exit(1)

sess=requests.Session()
sess.headers.update({'Accept':'application/json'})
base_url=base_url.rstrip('/')

def fetch_issue(ver):
    url=f"{base_url}/rest/api/{ver}/issue/{issue_key}?fields=assignee"
    try:
        r=sess.get(url,auth=(email,api_token),timeout=20)
    except Exception as e:
        return ('request_error',{'message':str(e)})
    if r.status_code==429:
        try:
            ra=float(r.headers.get('Retry-After','1'))
        except Exception:
            ra=1.0
        time.sleep(min(max(ra,0.1),interval_s))
        return ('retry',None)
    if r.status_code==404:
        return ('notfound',None)
    if not r.ok:
        return ('http_error',{'status':r.status_code,'text':r.text[:500]})
    try:
        data=r.json()
    except Exception:
        return ('parse_error',{'text':r.text[:500]})
    assignee=(data.get('fields') or {}).get('assignee')
    return ('ok',assignee)

start=time.time()
api_versions=['3','2']
ver_idx=0
while True:
    st,ass=fetch_issue(api_versions[ver_idx])
    if st=='retry':
        pass
    elif st=='notfound':
        if ver_idx==0:
            ver_idx=1; continue
        else:
            print(json.dumps({'error':'Issue not found','file':'main.py','issueKey':issue_key})); sys.exit(1)
    elif st in ('request_error','http_error','parse_error'):
        print(json.dumps({'error':'Jira API request failed','file':'main.py','details':ass})); sys.exit(1)
    elif st=='ok':
        if ass:
            match=False
            try:
                if user_account_id and ass.get('accountId')==user_account_id: match=True
                if not match and assignee_name and (ass.get('name')==assignee_name or ass.get('displayName')==assignee_name): match=True
                if not match and user_email and ass.get('emailAddress')==user_email: match=True
            except Exception:
                match=False
            if match:
                out={'status':'assigned','issueKey':issue_key,'assignee':{'accountId':ass.get('accountId'),'displayName':ass.get('displayName'),'emailAddress':ass.get('emailAddress'),'name':ass.get('name')}}
                print(json.dumps(out)); sys.exit(0)
    if time.time()-start>=timeout_s:
        print('{}'); sys.exit(0)
    time.sleep(interval_s)
